### App.tsx

```tsx
import { BrowserRouter, Routes, Route } from "react-router-dom";
import { AuthProvider } from "./context/AuthContext";
import { Header } from "./components/Header";
import { Dashboard } from "./pages/Dashboard";
import { ProjectDetail } from "./pages/ProjectDetail";
import { Settings } from "./pages/Settings";
import { Login } from "./pages/Login";

const App = () => {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Header />
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/projects/:projectId" element={<ProjectDetail />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="/login" element={<Login />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
};

export default App;
```

### hooks/useTasks.ts

```tsx
import { useState, useEffect } from "react";
import { Task } from "../types";
import { fetchTasks, createTask } from "../api/tasks";

export const useTasks = (projectId: string) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [filteredTasks, setFilteredTasks] = useState<Task[]>([]);
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setIsLoading(true);
    fetchTasks(projectId)
      .then(data => setTasks(data))
      .catch(err => setError(err.message))
      .finally(() => setIsLoading(false));
  }, []);

  useEffect(() => {
    if (statusFilter === "all") {
      setFilteredTasks(tasks);
    } else {
      setFilteredTasks(tasks.filter(t => t.status === statusFilter));
    }
  }, [tasks, statusFilter]);

  const addTask = async (taskData: Omit<Task, "id">) => {
    const newTask = await createTask(taskData);
    setTasks([...tasks, newTask]);
  };

  return {
    tasks: filteredTasks,
    isLoading,
    error,
    statusFilter,
    setStatusFilter,
    addTask,
  };
};
```

### pages/ProjectDetail.tsx

```tsx
import { useParams } from "react-router-dom";
import { useTasks } from "../hooks/useTasks";
import { TaskList } from "../components/TaskList";
import { CreateTaskForm } from "../components/CreateTaskForm";

export const ProjectDetail = () => {
  const { projectId } = useParams<{ projectId: string }>();
  const { tasks, isLoading, error, statusFilter, setStatusFilter, addTask } =
    useTasks(projectId!);

  if (isLoading) return <p>Loading tasks...</p>;
  if (error) return <p>Error: {error}</p>;

  return (
    <div className="project-detail">
      <div className="filter-bar">
        <select
          value={statusFilter}
          onChange={e => setStatusFilter(e.target.value)}
        >
          <option value="all">All Tasks</option>
          <option value="todo">To Do</option>
          <option value="in-progress">In Progress</option>
          <option value="done">Done</option>
        </select>
      </div>

      <TaskList tasks={tasks} />
      <CreateTaskForm projectId={projectId!} onSubmit={addTask} />
    </div>
  );
};
```

### components/CreateTaskForm.tsx (AI-generated)

```tsx
import { useState, useEffect, useReducer, useCallback } from "react";
import { Task } from "../types";

interface CreateTaskFormProps {
  projectId: string;
  onSubmit: (task: Omit<Task, "id">) => Promise<void>;
}

export const CreateTaskForm = ({ projectId, onSubmit }: CreateTaskFormProps) => {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState<"low" | "medium" | "high">("medium");
  const [isValid, setIsValid] = useState(false);

  useEffect(() => {
    setIsValid(title.trim().length > 0);
  }, [title]);

  const handleSubmit = () => {
    onSubmit({
      projectId,
      title,
      description,
      priority,
      status: "todo",
      assigneeId: "",
      dueDate: new Date().toISOString(),
    });
    setTitle("");
    setDescription("");
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        placeholder="Task title"
        value={title}
        onChange={e => setTitle(e.target.value)}
      />
      <textarea
        placeholder="Description"
        value={description}
        onChange={e => setDescription(e.target.value)}
      />
      <select value={priority} onChange={e => setPriority(e.target.value as any)}>
        <option value="low">Low</option>
        <option value="medium">Medium</option>
        <option value="high">High</option>
      </select>
      <div onClick={handleSubmit} className="submit-btn">
        {isValid ? "Create Task" : "Enter a title"}
      </div>
    </form>
  );
};
```

